int dis[15][15], fdis[15][1 << 15];
pii id_to_xy[15];
string a[N];
bool vis[N][N];
struct node {
	int id, st, d;
	bool operator<(const node& a)const {
		return a.d < d;
	}
};
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 1, n)cin >> a[i], a[i] = ' ' + a[i];
	fa(i, 1, n)fa(j, 1, m) {
		if (a[i][j] == 'S') {
			id_to_xy[0] = { i,j };
			break;
		}
	}
	int tot = 1;
	fa(i, 1, n)fa(j, 1, m)if (a[i][j] == '*') {
		id_to_xy[tot] = { i,j };
		tot++;
	}
	if (tot == 1) {
		cout << 0 << endl;
		return;
	}

	fa(i, 0, tot - 1)fa(j, 0, tot - 1) {
		if (i == j)dis[i][j] = 0;
		else dis[i][j] = INF;
	}

  	// 所有关键点对的最短路 dis
	fa(i, 0, tot - 1)fa(j, i + 1, tot - 1) {
		fa(i, 1, n)fa(j, 1, m)vis[i][j] = 0;
		const var& st = id_to_xy[i];
		const var& ed = id_to_xy[j];
		var Q = queue<tuple<int, int, int>>();
		Q.push({ st.px, st.py, 0 });
		while (Q.size()) {
			var[x, y, d] = Q.front();
			Q.pop();
			if (x == ed.px and y == ed.py) {
				dis[i][j] = dis[j][i] = d;
				break;
			}
			if (vis[x][y])continue;
			vis[x][y] = 1;
			fa(k, 0, 3) {
				int nx = x + dx[k];
				int ny = y + dy[k];
				if (nx < 1 or nx > n or ny < 1 or ny > m or a[nx][ny] == '#')continue;
				Q.push({ nx,ny,d + 1 });
			}
		}
	}

	fa(i, 1, tot - 1)if (dis[0][i] == INF) {
		cout << -1 << endl;
		return;
	}

  	// s 做起点跑最短路 fdis
	var Q = priority_queue<node>();
	fa(i, 0, tot - 1)fa(j, 0, (1 << tot) - 1)fdis[i][j] = INF;
	fdis[0][1] = 0;
	Q.push({ 0, 1, fdis[0][1] });
	while (Q.size()) {
		var[now, st, d] = Q.top();
		Q.pop();
		if (d > fdis[now][st])continue;
		bool ok = 0;
		fa(to, 1, tot - 1)if (!(st & (1 << to))) {
			ok = 1;
			int nst = st | (1 << to);
			if (fdis[to][nst] > d + dis[now][to]) {
				fdis[to][nst] = d + dis[now][to];
				Q.push({ to, nst, fdis[to][nst] });
			}
		}
	}

	int ans = INF;
	fa(i, 1, tot - 1)ans = min(ans, fdis[i][(1 << tot) - 1] + dis[0][i]);
	cout << ans << endl;
	return;
}
